+func TestConditionalCache(t *testing.T) {
+	// Given
+	cache, failsafeCache := policytesting.NewCache[string]()
+	stats := &policytesting.Stats{}
+	barPredicate := func(s string, err error) bool { return s == "bar" }
+
+	// When / Then
+	tests := []struct {
+		name           string
