+		},
+		{
+			name: "with non-matching condition",
+			cpb: policytesting.WithCacheStats(cachepolicy.Builder[string](failsafeCache), stats).WithKey("foo").
+				CacheIf(barPredicate),
+			result:         "baz",
+			expectedCaches: 0,
+		},
+	}
+
+	for _, tc := range tests {
+		t.Run(tc.name, func(t *testing.T) {
