+		{
+			name: "with global key",
+			executor: failsafe.NewExecutor[string](
+				policytesting.WithCacheStats(cachepolicy.Builder[string](failsafeCache).
+					WithKey("foo"), stats).
+					Build(),
+			),
+			expectedExecutions: 0,
+			expectedResult:     "bar",
+			expectedCaches:     1,
+			expectedHits:       1,
+			expectedMisses:     0,
