+		},
+		1, 1, testutil.ErrInvalidState, func() {
+			assert.Equal(t, 0, stats.Caches())
+			assert.Equal(t, 0, stats.CacheHits())
+			assert.Equal(t, 1, stats.CacheMisses())
+		})
+}
