+	execution, reset := testutil.ErrorNTimesThenReturn[any](testutil.ErrInvalidState, 2, "bar")
+	setup := func() context.Context {
+		cpStats.Reset()
+		rpStats.Reset()
+		reset()
+		clear(cache)
