+	cpStats := &policytesting.Stats{}
+	cache, failsafeCache := policytesting.NewCache[any]()
+	cp := policytesting.WithCacheStats[any](cachepolicy.Builder(failsafeCache), cpStats).WithKey("foo").Build()
