+		3, 3, "bar", func() {
+			assert.Equal(t, 3, rpStats.Executions())
+			assert.Equal(t, 2, rpStats.Retries())
+			assert.Equal(t, 1, cpStats.Caches())
+			assert.Equal(t, 0, cpStats.CacheHits())
+			assert.Equal(t, 1, cpStats.CacheMisses())
