+	testutil.TestGetSuccess(t, policytesting.SetupFn(cpStats), failsafe.NewExecutor[any](cp, rp), execution,
+		1, 0, "bar", func() {
+			assert.Equal(t, 0, cpStats.Caches())
+			assert.Equal(t, 1, cpStats.CacheHits())
+			assert.Equal(t, 0, cpStats.CacheMisses())
+		})
+}

